          <div className="flex items-center gap-3 mb-3">
            <div className="w-1.5 h-7 rounded-full bg-amber-500" />
            <h2 className="text-2xl font-bold">What clients say</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {topTestimonials.map((t: Record<string, unknown>) => (
              <div key={t.id} className="card card-pad card-lift card-lift">
                <div className="flex items-center gap-1 mb-2">
                  {Array.from({ length: t.rating || 5 }).map((_, i) => (
                    <Star key={i} className="w-4 h-4 fill-amber-400 text-amber-400" />
                  ))}
                </div>
                <p className="text-sm text-slate-700 dark:text-zinc-300 italic">
