import Database from "libsql";
import path from "node:path";
import fs from "node:fs";

// Persistent DB via Turso (libSQL) when configured; local SQLite file in dev.
// `libsql` exposes a better-sqlite3-compatible SYNCHRONOUS API, so the rest of
// the data layer (schema + call sites) is unchanged — only this opener swaps.
const TURSO_URL = process.env.TURSO_LIBSQL_URL;
const TURSO_TOKEN = process.env.TURSO_AUTH_TOKEN;

function openDb(): Database.Database {
  if (TURSO_URL) {
    // Remote, persistent (Turso). Sync API, better-sqlite3-compatible.
    return new Database(TURSO_URL, { authToken: TURSO_TOKEN }) as Database.Database;
  }
  // Dev / no-Turso fallback: local SQLite file (ephemeral on Vercel /tmp).
  const DATA_DIR = process.env.VERCEL ? "/tmp/data" : path.join(process.cwd(), "data");
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  return new Database(path.join(DATA_DIR, "hub.sqlite")) as Database.Database;
}

declare global {
  // eslint-disable-next-line no-var
  var __hub_db: Database.Database | undefined;
}

export const db: Database.Database = global.__hub_db ?? openDb();
try { db.pragma("busy_timeout=15000"); } catch { /* ignore */ }
try { db.pragma("journal_mode = WAL"); } catch { /* libSQL remote: not applicable */ }
try { db.pragma("foreign_keys = ON"); } catch { /* ignore if unsupported */ }
// Cache the connection globally — survives warm serverless invocations
global.__hub_db = db;

export function init() {
  db.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id TEXT PRIMARY KEY,
      email TEXT UNIQUE NOT NULL,
      name TEXT NOT NULL,
      password_hash TEXT NOT NULL,
      created_at INTEGER NOT NULL
    );
    CREATE TABLE IF NOT EXISTS sessions (
      token TEXT PRIMARY KEY,
      user_id TEXT NOT NULL,
      expires_at INTEGER NOT NULL,
      created_at INTEGER NOT NULL,
      FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
    );
    CREATE TABLE IF NOT EXISTS magic_link_tokens (
      token TEXT PRIMARY KEY,
      user_id TEXT NOT NULL,
      expires_at INTEGER NOT NULL,
      used INTEGER NOT NULL DEFAULT 0,
      created_at INTEGER NOT NULL,
      FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
    );
    CREATE INDEX IF NOT EXISTS idx_magic_link_user ON magic_link_tokens(user_id);
    CREATE TABLE IF NOT EXISTS login_attempts (
      id TEXT PRIMARY KEY,
      email TEXT NOT NULL,
      ip TEXT,
      ok INTEGER NOT NULL,
      created_at INTEGER NOT NULL
    );
    CREATE TABLE IF NOT EXISTS audit_log (
      id TEXT PRIMARY KEY,
      user_id TEXT,
      action TEXT NOT NULL,
      entity TEXT,
      entity_id TEXT,
      meta TEXT,
      created_at INTEGER NOT NULL
    );

    -- Outbox / provider tables (transactional email pipeline)
    CREATE TABLE IF NOT EXISTS email_outbox (
      id TEXT PRIMARY KEY,
      to_email TEXT NOT NULL,
      to_name TEXT,
      from_email TEXT,
      from_name TEXT,
      subject TEXT NOT NULL,
      body_html TEXT,
      body_text TEXT,
      reply_to TEXT,
      campaign_id TEXT,
      contact_id TEXT,
      automation_id TEXT,
      status TEXT NOT NULL DEFAULT 'queued',
      provider TEXT,
      provider_message_id TEXT,
      provider_response TEXT,
      last_error TEXT,
      attempts INTEGER NOT NULL DEFAULT 0,
      scheduled_for INTEGER,
      sent_at INTEGER,
      created_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_outbox_status ON email_outbox(status);
    CREATE INDEX IF NOT EXISTS idx_outbox_scheduled ON email_outbox(scheduled_for);
    CREATE TABLE IF NOT EXISTS email_events (
      id TEXT PRIMARY KEY,
      outbox_id TEXT NOT NULL,
      kind TEXT NOT NULL,
      url TEXT,
      meta TEXT,
      created_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_email_events_outbox ON email_events(outbox_id);
    CREATE TABLE IF NOT EXISTS provider_keys (
      id TEXT PRIMARY KEY,
      provider TEXT NOT NULL,
      label TEXT,
      config TEXT,
      active INTEGER NOT NULL DEFAULT 0,
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL
    );

    -- Strategy / agent tables
    CREATE TABLE IF NOT EXISTS brand_stories (
      id TEXT PRIMARY KEY,
      workspace TEXT,
      title TEXT NOT NULL,
      hook TEXT,
      problem TEXT,
