import { NextRequest } from "next/server";
import { json, err, readJson, listRows, insertRow, updateRow, deleteRow } from "@/lib/api-helpers";
import { now, uid } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function GET() {
  const rows = listRows("proposals");
  return json({ rows });
}

export async function POST(req: NextRequest) {
  const body = await readJson<Record<string, unknown>>(req);
  if (!body || !body.client_name || !body.title) {
    return err("client_name and title required");
  }
  const id = uid("prop_");
  const t = now();
  const row = insertRow("proposals", {
    id,
    workspace: body.workspace || "default",
    client_id: body.client_id || null,
    client_name: body.client_name,
    title: body.title,
    line_items: Array.isArray(body.line_items) ? body.line_items : [],
    total: typeof body.total === "number" ? body.total : 0,
    currency: body.currency || "USD",
    status: body.status || "draft",
    due_date: body.due_date || null,
    terms: body.terms || null,
    cover_letter: body.cover_letter || null,
    token: body.token || uid("token_"),
    sender_name: body.sender_name || null,
    sender_email: body.sender_email || null,
    created_at: t,
    updated_at: t,
  });
  return json(row, 201);
}

