export const dynamic = "force-dynamic";

export async function GET(_req: NextRequest, { params }: { params: { id: string } }) {
  const row = getRow("proposals", params.id);
  if (!row) return err("Proposal not found", 404);
  return json(row);
}

export async function PATCH(req: NextRequest, { params }: { params: { id: string } }) {
  const body = await req.json().catch(() => null);
  if (!body) return err("Invalid body", 400);
  const allowed = [
    "title", "client_name", "client_id", "line_items", "total", "currency",
    "status", "due_date", "terms", "cover_letter", "sender_name", "sender_email",
  ];
  const patch: Record<string, unknown> = {};
  for (const k of allowed) {
    if (k in body) patch[k] = body[k];
  }
  patch.updated_at = Date.now();
  const row = updateRow("proposals", params.id, patch);
  return json(row);
}

export async function DELETE(_req: NextRequest, { params }: { params: { id: string } }) {
  deleteRow("proposals", params.id);
  return json({ ok: true });
}

