import { NextRequest } from "next/server";
import { json, err, getRow, updateRow, insertRow } from "@/lib/api-helpers";
import { now, uid } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function POST(req: NextRequest, { params }: { params: { id: string } }) {
  const proposal = getRow("proposals", params.id);
  if (!proposal) return err("Proposal not found", 404);

  const body = await req.json().catch(() => null);
  if (!body || !body.signer_name || !body.signer_email) {
    return err("signer_name and signer_email required");
  }

  const method = body.method === "canvas_signature" ? "canvas_signature" : "click_accept";
  const signatureData = {
    method,
    name: body.signer_name,
    email: body.signer_email,
    ip: body.ip || null,
    timestamp: new Date().toISOString(),
    ...(method === "canvas_signature" ? { image: body.image || null } : {}),
  };

  const sigId = uid("sig_");
  insertRow("proposal_signatures", {
    id: sigId,
    proposal_id: params.id,
    signer_name: body.signer_name,
    signer_email: body.signer_email,
    signed_at: now(),
    ip: body.ip || null,
    method,
    signature_data: JSON.stringify(signatureData),
    created_at: now(),
  });

  const row = updateRow("proposals", params.id, {
    status: "accepted",
    accepted_at: now(),
    updated_at: now(),
  });

  return json({ proposal: row, signature: { id: sigId, method, signature_data: signatureData } });
}

