+    "title", "body", "status", "start_date", "end_date", "auto_renew",
+    "client_name", "client_id", "proposal_id", "fee", "currency",
+  ];
+  const patch: Record<string, unknown> = {};
+  for (const k of allowed) {
+    if (k in body) patch[k] = body[k];
+  }
+  patch.updated_at = Date.now();
+  const row = updateRow("contracts", params.id, patch);
+  return json(row);
+}
+
+export async function DELETE(_req: NextRequest, { params }: { params: { id: string } }) {
+  deleteRow("contracts", params.id);
+  return json({ ok: true });
+}

