import { NextRequest } from "next/server";
import { json, err, getRow, updateRow } from "@/lib/api-helpers";
import { now } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function POST(req: NextRequest, { params }: { params: { id: string } }) {
  const contract = getRow("contracts", params.id);
  if (!contract) return err("Contract not found", 404);

  const body = await req.json().catch(() => null);
  if (!body || !body.signer_name || !body.signer_email) {
    return err("signer_name and signer_email required");
  }

  const method = body.method === "click_accept" ? "click_accept" : "canvas_signature";
  const signatureData = {
    method,
    name: body.signer_name,
    email: body.signer_email,
    ip: body.ip || null,
    timestamp: new Date().toISOString(),
    ...(method === "canvas_signature" ? { image: body.image || null } : {}),
  };

  const row = updateRow("contracts", params.id, {
    status: "signed",
    signed_at: now(),
    signature_data: JSON.stringify(signatureData),
    updated_at: now(),
  });

  return json({ contract: row, signature_data: signatureData });
}

