"use client";
import { useState } from "react";
import { useFetch, apiFetch } from "@/components/useFetch";
import { Plus, FileText, Send, CheckCircle2, XCircle, Search, ExternalLink } from "lucide-react";
import { Modal } from "@/components/Modal";
import clsx from "clsx";

const STATUS_COLORS: Record<string, string> = {
  draft: "bg-zinc-800/50 text-zinc-400",
  sent: "bg-[hsl(210,75%,60%)]/20 text-[hsl(210,75%,60%)]",
  viewed: "bg-[hsl(38,85%,58%)]/20 text-[hsl(38,85%,58%)]",
  accepted: "bg-[hsl(145,70%,55%)]/20 text-[hsl(145,70%,55%)]",
  expired: "bg-zinc-800/50 text-zinc-500 line-through",
};

export default function ProposalsPage() {
  const { data, reload } = useFetch<{ rows: Record<string, unknown>[] }>("/api/finance/proposals");
  const [showNew, setShowNew] = useState(false);
  const [filterStatus, setFilterStatus] = useState("");
  const [sendingId, setSendingId] = useState<string | null>(null);

  const rows = (data?.rows || []) as Record<string, unknown>[];
  const filtered = rows.filter((r) => !filterStatus || r.status === filterStatus);

  async function createProposal(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    await apiFetch("/api/finance/proposals", {
      method: "POST",
      body: JSON.stringify({
        client_name: fd.get("client_name"),
        client_id: fd.get("client_id") || null,
        title: fd.get("title"),
        total: Number(fd.get("total") || 0),
        currency: fd.get("currency") || "USD",
        terms: fd.get("terms") || "",
        cover_letter: fd.get("cover_letter") || "",
        sender_name: fd.get("sender_name") || "",
        sender_email: fd.get("sender_email") || "",
      }),
    });
    setShowNew(false);
    reload();
  }

  async function sendProposal(id: string) {
    setSendingId(id);
    await apiFetch(`/api/finance/proposals/${id}/send`, { method: "POST" });
    setSendingId(null);
    reload();
  }

  return (
    <div className="space-y-6">
      <header className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold flex items-center gap-2">
            <FileText className="w-5 h-5" /> Proposals
          </h1>
          <p className="text-sm muted mt-1">
            Create, send, and track proposals. Click accept to e-sign.
          </p>
        </div>
        <button onClick={() => setShowNew(true)} className="btn btn-primary">
          <Plus className="w-4 h-4" /> New proposal
        </button>
      </header>

      <div className="flex items-center gap-2">
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
          className="btn"
        >
          <option value="">All statuses</option>
          <option value="draft">Draft</option>
          <option value="sent">Sent</option>
          <option value="accepted">Accepted</option>
          <option value="expired">Expired</option>
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filtered.map((p) => (
          <div key={p.id as string} className="card card-pad card-lift">
            <div className="flex items-center justify-between mb-2">
              <div className="font-bold text-lg">{p.title as string}</div>
              <span className={clsx("text-[10px] font-bold uppercase px-2 py-1 rounded", STATUS_COLORS[p.status as string] || STATUS_COLORS.draft)}>
                {p.status as string}
              </span>
            </div>
            <div className="text-sm muted mb-1">Client: {p.client_name as string}</div>
            <div className="text-sm muted mb-3">
              {(p.total as number) > 0 && (
                <span className="font-semibold text-[rgb(var(--text))]">
                  {p.currency as string} {(p.total as number).toFixed(2)}
                </span>
              )}
            </div>
            <div className="flex items-center gap-2">
              <Link href={`/finance/proposals/${p.id as string}`} className="btn text-xs">
                Open
              </Link>
              {p.status === "draft" && (
                <button
                  onClick={() => sendProposal(p.id as string)}
                  disabled={sendingId === p.id}
                  className="btn btn-primary text-xs"
                >
                  {sendingId === p.id ? "Sending..." : <><Send className="w-3 h-3" /> Send</>}
                </button>
              )}
              {(p.status === "sent" || p.status === "accepted") && (
                <Link href={`/finance/proposals/${p.id as string}`} className="btn text-xs">
                  View
                </Link>
              )}
            </div>
          </div>
        ))}
      </div>

      <Modal open={showNew} onClose={() => setShowNew(false)} title="New Proposal">
        <form onSubmit={createProposal} className="space-y-3">
          <div>
            <label className="block text-xs font-semibold mb-1">Client name</label>
            <input name="client_name" required className="input" />
          </div>
          <div>
            <label className="block text-xs font-semibold mb-1">Client ID (optional)</label>
            <input name="client_id" className="input" />
          </div>
          <div>
            <label className="block text-xs font-semibold mb-1">Title</label>
            <input name="title" required className="input" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-semibold mb-1">Total</label>
              <input name="total" type="number" step="0.01" defaultValue="0" className="input" />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">Currency</label>
              <select name="currency" className="input">
                <option value="USD">USD</option>
                <option value="EUR">EUR</option>
                <option value="GBP">GBP</option>
              </select>
            </div>
          </div>
          <div>
            <label className="block text-xs font-semibold mb-1">Terms</label>
            <textarea name="terms" rows={3} className="input" />
          </div>
          <div>
            <label className="block text-xs font-semibold mb-1">Cover letter</label>
            <textarea name="cover_letter" rows={3} className="input" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-semibold mb-1">Sender name</label>
              <input name="sender_name" className="input" />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">Sender email</label>
              <input name="sender_email" type="email" className="input" />
            </div>
          </div>
          <div className="flex justify-end gap-2 pt-2">
            <button type="button" onClick={() => setShowNew(false)} className="btn">Cancel</button>
            <button type="submit" className="btn btn-primary">Create proposal</button>
          </div>
        </form>
      </Modal>
    </div>
  );
}
